## 角色设置
角色设置: {
  "characters": {
    "protagonist": {
      "角色功能": "主角",
      "external": {
        "physiological": {
          "姓名": "刘老栓",
          "身高": "167厘米",
          "体重": "58公斤",
          "年龄": "44岁",
          "外貌": "黑瘦，颧骨高凸，常年风吹日晒导致皮肤粗糙如树皮，双手布满老茧和裂口，头发花白稀疏，眼神浑浊但偶尔闪出倔强的光。常穿一件打了无数补丁的灰布褂子，腰间系一根草绳。"
        },
        "psychological": {
          "感情生活": "丧偶十年，独身未再娶，与15岁的儿子刘小栓相依为命，对亡妻的怀念深埋心底，偶尔在深夜对着她的遗像自言自语。",
          "道德标准": "信奉‘本分做人，不欠不贪’，认为种地养猪是天经地义，从不占人便宜，但也绝不接受施舍。对村里偷鸡摸狗的行为深恶痛绝。",
          "情商智商": "情商低，不善言辞，不懂察言观色，常因沉默被误解为冷漠；智商中等偏下，只懂农活和养猪的基本常识，对抽象概念理解缓慢，但有一种朴素的生存直觉，能感知天气和土地的变化。"
        },
        "social": {}
      },
      "internal": {
        "人物创伤": "十年前妻子因难产大出血，村里没有医生，山路又远，眼睁睁看着她死在床上，婴儿也没保住。此后他认定‘命里注定的事，挣扎也没用’，变得愈发沉默寡言，把全部情感寄托在儿子和那头猪身上。",
        "人物缺陷": "极度固执，拒绝任何改变。即使猪被风吹走，他最初的反应也不是追，而是蹲在猪圈废墟前发呆，觉得‘风要带走的东西，找也找不回’。这种被动性让他几乎失去行动力。",
        "人物性格": "隐忍、木讷、认命，但骨子里有一丝对‘活着’的执着。平时像一块石头，不主动惹事，但被逼到绝路时会爆发出惊人的倔强。",
        "人物选择": "在猪飞走后，他最初选择接受命运，准备砍柴过冬；但当儿子刘小栓哭着说‘没肉吃会饿死’时，他被迫拿起绳子和扁担，踏上寻找猪的路。",
        "人物动机": "找回猪是为了让儿子在冬天有肉吃、有年货换，避免儿子重蹈妻子因贫穷而死的覆辙。这不是为了尊严或反抗命运，纯粹是一个父亲最底线的生存本能。"
      }
    },
    "antagonist": {
      "角色功能": "对手",
      "external": {
        "physiological": {
          "姓名": "赵大富",
          "身高": "172厘米",
          "体重": "75公斤",
          "年龄": "50岁",
          "外貌": "身材粗壮，圆脸，油光满面，脖子上常年挂着一条脏兮兮的汗巾。穿着村里少见的的确良衬衫，袖口卷到肘部，手腕上戴一块旧电子表。眼睛小而精明，笑起来眯成一条缝。",
        },
        "psychological": {
          "感情生活": "娶了隔壁村的胖女人，生了三个女儿，没有儿子，因此常被村里人背后嘲笑‘绝户’，这成为他心中最大的隐痛。对妻子呼来喝去，但畏惧岳父家的势力。",
          "道德标准": "实用主义道德，认为‘钱就是道理’，只要能赚钱，骗人、偷窃、威胁都可以接受。表面上敬鬼神，实际上只信自己的算盘。",
          "情商智商": "情商高，善于察言观色、拉拢人心，能用几根烟或几句好话让村民帮他干活；智商中等，精于算计，但缺乏长远眼光，只盯着眼前利益。"
        },
        "social": {}
      },
      "internal": {
        "人物创伤": "年轻时去县城打工，被老板骗光积蓄，还被打断一根肋骨，从此认定‘老实人吃亏’，发誓再不做亏本买卖。回到村里后，他靠倒卖山货和放高利贷成了唯一的‘富人’，但内心始终恐惧回到赤贫。",
        "人物缺陷": "贪婪且短视，一旦看到利益就失去理智。当猪飞走后，他第一个想到的不是帮忙，而是‘活猪能卖多少钱，死猪能卖多少肉’，并试图利用村民的迷信来垄断‘神猪’的解释权。",
        "人物性格": "精明、圆滑、自私，表面上对谁都很客气，但骨子里冷酷无情。喜欢在酒桌上吹嘘自己在县城的见闻，以此确立在村里的权威。",
        "人物选择": "在猪飞走后，他立刻组织几个游手好闲的村民，声称‘神猪是上天赐给黄土坳的福气，不能让外村人抢走’，实际上是想抓住猪后拉到县城卖高价，并借此抬高自己在村里的地位。",
        "人物动机": "抓住猪，卖掉换钱，然后用这笔钱去县城买个儿子，解决‘绝户’的耻辱，同时巩固自己在村里的经济控制权。他害怕猪被刘老栓找回，因为那意味着他失去了一个翻身的机会。"
      }
    },
    "emotional_core": {
      "角色功能": "情感核心人物",
      "external": {
        "physiological": {
          "姓名": "刘小栓",
          "身高": "152厘米",
          "体重": "40公斤",
          "年龄": "15岁",
          "外貌": "瘦弱，营养不良导致面色蜡黄，头发枯黄打结，眼睛大而无神，但偶尔会闪过一丝不属于这个年纪的忧郁。穿一件明显偏大的破旧蓝布衫，裤腿挽了好几截。",
        },
        "psychological": {
          "感情生活": "与父亲相依为命，内心极度渴望母爱，但从不表达。偷偷珍藏了母亲的一张黑白照片，每晚睡前都会看一会儿。对村里同龄孩子既羡慕又疏离，因为父亲沉默寡言，他也很少说话。",
          "道德标准": "单纯善良，相信‘好人会有好报’，但父亲的沉默让他对这句话产生怀疑。他同情村里所有受苦的人和动物，曾偷偷给邻居家的瘦狗喂食。",
          "情商智商": "情商高于父亲，能敏锐感知别人的情绪，但不知如何回应；智商普通，上学到三年级就辍学帮家里干活，识字不多，但擅长观察自然：他能分辨不同鸟的叫声，知道哪块地的蚂蚁搬家预示下雨。"
        },
        "social": {}
      },
      "internal": {
        "人物创伤": "母亲死时他只有五岁，记忆里只剩下母亲苍白的脸和父亲撕心裂肺的哭声。他始终认为母亲的死是因为家里太穷、没有钱请医生，因此对‘贫穷’有一种刻骨的恐惧。",
        "人物缺陷": "过度依赖父亲，缺乏独立行动的勇气。当猪飞走后，他第一反应是哭，而不是思考怎么办。他害怕父亲像当年对待母亲一样，选择沉默地接受。",
        "人物性格": "敏感、内向、早熟。平时像一只受惊的小兽，躲在父亲身后，但在关键时刻会爆发出超越年龄的坚韧。",
        "人物选择": "当父亲最初放弃寻找猪时，他第一次对父亲发火，哭着喊出‘我们不是还有腿吗？’这个选择迫使父亲动身，也标志着他开始尝试打破命运的沉默。",
        "人物动机": "找回猪，不是为了吃肉，而是为了证明‘有些事情是可以改变的’。他害怕如果连猪都找不回来，父亲会彻底变成一具行尸走肉，而他也会像母亲一样，在沉默中死去。"
      }
    },
    "ally": {
      "角色功能": "盟友",
      "external": {
        "physiological": {
          "姓名": "王瘸子",
          "身高": "165厘米",
          "体重": "55公斤",
          "年龄": "60岁",
          "外貌": "左腿小儿麻痹症留下的残疾，走路一瘸一拐，拄一根自制的酸枣木拐杖。身材干瘦，背微驼，脸上皱纹深刻，像黄土高坡的沟壑。常年戴一顶破草帽，眼神浑浊但偶尔透出狡黠的智慧。",
        },
        "psychological": {
          "感情生活": "鳏居三十年，年轻时娶过一房媳妇，因他残疾且穷，三年后跟货郎跑了，留下一个女儿，女儿十八岁时嫁到外村，一年也回不了一次。他独自住在村尾的破窑洞里，养了几只鸡。",
          "道德标准": "信奉‘人不犯我，我不犯人’，但若有人欺负他，他会记仇一辈子。他尊重刘老栓的‘本分’，鄙视赵大富的‘投机’。对村里的事总是一副看透了的姿态，但内心渴望被尊重。",
          "情商智商": "情商中等，能听懂话里有话，但懒得应付；智商中等偏上，年轻时读过两年私塾，认得一些字，是村里少数能算清账的人，常帮村民写信、算账，但从不收钱，只讨一碗水喝。"
        },
        "social": {}
      },
      "internal": {
        "人物创伤": "三十年前，他因残疾被妻子抛弃，女儿也被带走，从此对‘家庭’和‘女人’充满不信任。他认定‘世道对残疾人不公平’，于是用冷漠和嘲讽筑起一道墙，拒绝任何人的同情。",
        "人物缺陷": "愤世嫉俗，说话刻薄，喜欢用挖苦的方式表达关心。当刘老栓来找他帮忙时，他第一反应是冷笑：‘猪都能飞了，你还能追得上？’但实际他会默默准备好干粮和绳子。",
        "人物性格": "外冷内热，表面尖酸，内心柔软。他喜欢坐在村口的大石头上晒太阳，看人来人往，嘴里叼着旱烟袋，像一尊沉默的雕像。",
        "人物选择": "当刘老栓决定出发找猪时，他主动提出同行，理由是‘你一个人走山路，摔死了都没人收尸’。实际上，他是在用行动弥补自己当年没能留住妻女的遗憾。",
        "人物动机": "帮助刘老栓找回猪，是为了证明‘瘸子也能干成事’，打破村里人对他‘废人’的标签。更深一层，他希望通过这次行动，重新找回自己失去的尊严，哪怕只是一点点。"
      }
    },
    "mirror": {
      "角色功能": "镜像人物",
      "external": {
        "physiological": {
          "姓名": "张屠户",
          "身高": "178厘米",
          "体重": "90公斤",
          "年龄": "45岁",
          "外貌": "虎背熊腰，满脸横肉，络腮胡刮得发青，一双大手粗壮有力，指甲缝里永远嵌着洗不掉的猪油和血渍。常穿一件油腻腻的皮围裙，腰间挂一把磨得锃亮的杀猪刀。",
        },
        "psychological": {
          "感情生活": "娶了村里的‘懒婆娘’李翠花，两人育有一子，但儿子天生痴呆，八岁了还不会说话。他表面粗鲁，实则对儿子极尽温柔，每天收工后都会抱着儿子去村口看夕阳。",
          "道德标准": "信奉‘杀生不造孽，造孽的是活人’。他杀猪从不折磨，一刀毙命，但收钱时也从不手软。他认为自己干的是一份正当营生，不偷不抢，比赵大富那种人干净。",
          "情商智商": "情商中等，脾气暴躁，容易发火，但发完就忘；智商中等，精通屠宰和猪肉生意，但对其他事情一窍不通，容易被赵大富的花言巧语利用。"
        },
        "social": {}
      },
      "internal": {
        "人物创伤": "儿子的痴呆是他心中永远的痛。他找过神婆、拜过庙、喝过偏方，但毫无用处。他认定这是自己杀生太多的报应，因此每次杀猪前都会默念一段‘往生咒’，但杀猪时依然毫不手软。",
        "人物缺陷": "迷信且易被煽动。当猪飞走后，他最初的反应是恐惧，认为这是‘不祥之兆’，但赵大富告诉他‘神猪的血能治百病’，他便动了杀心，想用猪血给儿子治病。",
        "人物性格": "粗犷、暴躁、迷信，但内心有一块柔软的地方留给儿子。他相信‘以命换命’的朴素逻辑，认为只要心诚，就能改变命运。",
        "人物选择": "在赵大富的怂恿下，他决定参与追捕猪，并计划在抓到后立刻宰杀，用猪血给儿子洗澡。这个选择让他与刘老栓发生直接冲突，成为猪的‘致命威胁’。",
        "人物动机": "杀死猪，用猪血给儿子治病，试图打破儿子痴呆的‘诅咒’。他心底深处知道这可能没用，但作为一个父亲，他无法忍受什么都不做。他实际上是刘老栓的‘镜像’：同样的父亲身份，同样的绝望，但选择了完全不同的行动路径。"
      }
    }
  }
}
